      let dBInstanceClass = field_map json "DBInstanceClass" String_.of_json in
      let sourceDBInstanceIdentifier =
        field_map_exn json "SourceDBInstanceIdentifier" String_.of_json in
      let dBInstanceIdentifier =
        field_map_exn json "DBInstanceIdentifier" String_.of_json in
      make ?customIamInstanceProfile ?maxAllocatedStorage ?replicaMode
        ?domainIAMRoleName ?domain ?deletionProtection
        ?useDefaultProcessorFeatures ?processorFeatures
        ?enableCloudwatchLogsExports ?performanceInsightsRetentionPeriod
        ?performanceInsightsKMSKeyId ?enablePerformanceInsights
        ?enableIAMDatabaseAuthentication ?preSignedUrl ?kmsKeyId
        ?monitoringRoleArn ?monitoringInterval ?copyTagsToSnapshot
        ?storageType ?vpcSecurityGroupIds ?dBSubnetGroupName ?tags
        ?publiclyAccessible ?dBParameterGroupName ?optionGroupName ?iops
        ?autoMinorVersionUpgrade ?multiAZ ?port ?availabilityZone
        ?dBInstanceClass ~sourceDBInstanceIdentifier ~dBInstanceIdentifier ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Creates a new DB instance that acts as a read replica for an existing source DB instance. You can create a read replica for a DB instance running MySQL, MariaDB, Oracle, PostgreSQL, or SQL Server. For more information, see Working with Read Replicas in the Amazon RDS User Guide. Amazon Aurora doesn't support this action. Call the CreateDBInstance action to create a DB instance for an Aurora DB cluster. All read replica DB instances are created with backups disabled. All other DB instance attributes (including DB security groups and DB parameter groups) are inherited from the source DB instance, except as specified. Your source DB instance must have backup retention enabled."]
module CreateDBInstanceMessage =
  struct
    type nonrec t =
